const express = require('express');
const crypto = require('crypto');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.urlencoded({ extended: true }));
app.use(bodyParser.json());

const clients = {
  'client123': {
    clientId: 'client123',
    clientSecret: 'secret456',
    redirectUris: ['http://localhost:3001/callback', 'http://localhost:3002/callback']
  }
};

const users = {
  'user1': { username: 'user1', password: 'password1' }
};

const authorizationCodes = new Map();
const accessTokens = new Map();

app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;

  if (!response_type || response_type !== 'code') {
    return res.status(400).json({ error: 'invalid_request', error_description: 'response_type must be code' });
  }

  if (!client_id || !clients[client_id]) {
    return res.status(400).json({ error: 'invalid_client', error_description: 'Invalid client_id' });
  }

  if (!redirect_uri || !clients[client_id].redirectUris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri' });
  }

  res.send(`
    <html>
      <body>
        <h2>Authorization Request</h2>
        <p>Client ${client_id} is requesting access</p>
        <p>Scope: ${scope || 'default'}</p>
        <form method="POST" action="/authorize">
          <input type="hidden" name="client_id" value="${client_id}" />
          <input type="hidden" name="redirect_uri" value="${redirect_uri}" />
          <input type="hidden" name="scope" value="${scope || ''}" />
          <input type="hidden" name="state" value="${state || ''}" />
          <div>
            <label>Username: <input type="text" name="username" required /></label>
          </div>
          <div>
            <label>Password: <input type="password" name="password" required /></label>
          </div>
          <button type="submit" name="action" value="approve">Approve</button>
          <button type="submit" name="action" value="deny">Deny</button>
        </form>
      </body>
    </html>
  `);
});

app.post('/authorize', (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password, action } = req.body;

  if (!users[username] || users[username].password !== password) {
    return res.status(401).send('Invalid credentials');
  }

  if (action !== 'approve') {
    const errorUrl = `${redirect_uri}?error=access_denied&error_description=User denied authorization${state ? '&state=' + state : ''}`;
    return res.redirect(errorUrl);
  }

  const code = crypto.randomBytes(32).toString('hex');
  
  authorizationCodes.set(code, {
    clientId: client_id,
    redirectUri: redirect_uri,
    username: username,
    scope: scope,
    expiresAt: Date.now() + 600000,
    used: false
  });

  setTimeout(() => {
    authorizationCodes.delete(code);
  }, 600000);

  const redirectUrl = `${redirect_uri}?code=${code}${state ? '&state=' + state : ''}`;
  res.redirect(redirectUrl);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!client_id || !client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const client = clients[client_id];
  if (!client || client.clientSecret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'code is required' });
  }

  const authCode = authorizationCodes.get(code);

  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  }

  if (authCode.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code already used' });
  }

  if (authCode.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (authCode.clientId !== client_id) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client mismatch' });
  }

  if (authCode.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  authCode.used = true;

  const accessToken = crypto.randomBytes(32).toString('hex');
  const refreshToken = crypto.randomBytes(32).toString('hex');

  accessTokens.set(accessToken, {
    clientId: client_id,
    username: authCode.username,
    scope: authCode.scope,
    expiresAt: Date.now() + 3600000
  });

  authorizationCodes.delete(code);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authCode.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'token_expired' });
  }

  res.json({
    sub: tokenData.username,
    username: tokenData.username,
    scope: tokenData.scope
  });
});

